#include <stdio.h>

int main(void) {
    char text[42];
    if (fgets(text, sizeof text, stdin) == NULL) return 1;
    size_t length = 0;
    while (text[length] != '\0' && text[length] != '\n') ++length;
    if (text[length] == '\n') text[length] = '\0';
    printf("%zu\n", length);
    return 0;
}
